import React from "react";

interface Props {
  activeFile: string | null;
}

const fileContents: Record<string, string> = {
  "README.md": `# Hi, I'm Karthik\nData / AI engineer focused on building production-grade systems.\nOpen a folder or ask a question.`,
  "tools.css": `/* CSS styling for portfolio */`,
  "contact.css": `/* Contact section styles */`,
};

export default function EditorPanel({ activeFile }: Props) {
  if (!activeFile) {
    return (
      <div className="flex items-center justify-center h-full text-neutral-500">
        Welcome! Click a file to open.
      </div>
    );
  }

  return (
    <div className="h-full p-4 overflow-auto bg-black text-green-400 border border-neutral-800 rounded-xl">
      <pre>{fileContents[activeFile]}</pre>
    </div>
  );
}
