import React from "react";

interface Props {
  onOpenFile: (file: string) => void;
}

const folders = ["projects", "experience"];
const files = ["README.md", "tools.css", "contact.css"];

export default function LeftSidebar({ onOpenFile }: Props) {
  return (
    <div className="flex flex-col h-full p-4 border-r border-neutral-800 bg-neutral-900 text-neutral-200">
      <h2 className="mb-2 text-sm font-bold uppercase">Folders</h2>
      {folders.map((f) => (
        <button
          key={f}
          className="mb-1 text-left px-2 py-1 hover:bg-neutral-700 rounded"
        >
          {f}
        </button>
      ))}

      <h2 className="mt-4 mb-2 text-sm font-bold uppercase">Files</h2>
      {files.map((f) => (
        <button
          key={f}
          onClick={() => onOpenFile(f)}
          className="mb-1 text-left px-2 py-1 hover:bg-neutral-700 rounded"
        >
          {f}
        </button>
      ))}
    </div>
  );
}
