import React, { useState } from "react";

export default function ChatPanel() {
  const [model, setModel] = useState("Tech Lead");

  return (
    <div className="flex flex-col h-full border-l border-neutral-800 bg-neutral-900 p-4 text-white">
      <div className="mb-4 flex gap-2">
        {["Recruiter", "Tech Lead", "Executive"].map((m) => (
          <button
            key={m}
            className={`px-3 py-1 rounded ${
              model === m ? "bg-green-600" : "bg-neutral-700"
            }`}
            onClick={() => setModel(m)}
          >
            {m}
          </button>
        ))}
      </div>
      <div className="flex-1 overflow-auto text-neutral-300">
        <p>Ask me about my work from a {model} perspective.</p>
        <textarea
          placeholder="Type a question..."
          className="w-full mt-2 p-2 rounded bg-neutral-800 text-white resize-none h-24"
        />
      </div>
    </div>
  );
}
